import styled from "styled-components";
import { Link } from "react-router-dom";

const Footer = () => {
  return(
    <Container>

          {/* Logo */}
      <Logo to="/">
        <img src="/images/Tree.png" alt="Logo" />
      </Logo>

    
      {/* Menu de Navegação */}
      <NavMenu>
          

        <StyledLink to="/">
          <span>Home</span>
        </StyledLink>

        <StyledLink to="/produtos">
          <span>Produtos</span>
        </StyledLink>

        <StyledLink to="/login">
          <span>Login</span>
        </StyledLink>

      </NavMenu>




    </Container>
  );
};



// Styled-Components

const Container = styled.div`
  background-color: #222222;
  width: 100%;
  height: 30vh;
  display: flex;
  flex-direction: column;
  justify-content: space-between;
  padding: 0 30px;
  align-items: center;
`;

// Logo agora é Link
const Logo = styled(Link)`
  width: 80px;

  display: flex;
  align-items: center;

  img {
    width: 90%;
    border-radius: 50px;
      margin: 30px
  }
`;



// Link estilizado
const StyledLink = styled(Link)`
  text-decoration: none;
  display: flex;
  align-items: center;
  padding: 0 12px;
  font-family: 'Space Grotesk', sans-serif;
  letter-spacing: 1px;


  span {
    color: rgb(90, 206, 186);
    font-size: 18px;
    letter-spacing: 1px;
    line-height: 1.08;
    padding: 1px 0;
    white-space: nowrap;
    position: relative;

    &:before {
      background-color: rgb(255, 0, 0);
      border-radius: 0 0 4px 4px;
      bottom: -6px;
      content: "";
      height: 2px;
      left: 0;
      opacity: 0;
      position: absolute;
      right: 0;
      transform-origin: left center;
      transform: scaleX(0);
      transition: all 250ms cubic-bezier(0.25, 0.46, 0.45, 0.94);
      visibility: hidden;
    }
  }

  &:hover span:before {
    transform: scaleX(1);
    visibility: visible;
    opacity: 1;
  }
`;

const NavMenu = styled.div`
  align-items: center;
  display: flex;
  flex-flow: row nowrap;
  height: 100%;
  margin-left: 30px;

  @media (max-width: 548px) {
    display: none;
  }
`;


export default Footer;
